#include <iostream>

using namespace std;

template <typename T>
T add(T a, T b)
{
    return a + b;
}

int main()
{
    cout << add(2, 3) << endl;
    cout << add(2.5, 3.5) << endl;

    return 0;
}

template <typename T>
class Box
{
private:
    T value;

public:
    Box(T v) { value = v; }
    T getValue() { return value; }
};

Box<int> intBox(42);
Box<string> stringBox("Hello");

